package com.enterprise.app.service;

import com.enterprise.app.domain.AppUser;
import com.enterprise.app.repository.AppUserRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.Optional;
import java.util.Set;

@Service
public class UserService {

    private final AppUserRepository userRepository;

    public UserService(AppUserRepository userRepository) {
        this.userRepository = userRepository;
    }

    @Transactional
    public AppUser createUser(String username, String email, String passwordHash, Set<String> roles) {
        if (userRepository.existsByUsername(username)) {
            throw new IllegalArgumentException("Username already exists");
        }
        if (userRepository.existsByEmail(email)) {
            throw new IllegalArgumentException("Email already exists");
        }
        AppUser u = new AppUser();
        u.setUsername(username);
        u.setEmail(email);
        u.setPasswordHash(passwordHash);
        u.setEnabled(true);
        if (roles != null) u.setRoles(roles);
        return userRepository.save(u);
    }

    @Transactional(readOnly = true)
    public Optional<AppUser> findById(Long id) {
        return userRepository.findById(id);
    }

    @Transactional(readOnly = true)
    public Optional<AppUser> findByUsername(String username) {
        return userRepository.findByUsername(username);
    }

    @Transactional
    public AppUser disableUser(Long id) {
        AppUser u = userRepository.findById(id).orElseThrow(() -> new IllegalArgumentException("User not found"));
        u.setEnabled(false);
        return userRepository.save(u);
    }
}

package com.enterprise.app.service;

import com.enterprise.app.domain.AppUser;
import com.enterprise.app.domain.Transaction;
import com.enterprise.app.domain.TransactionStatus;
import com.enterprise.app.repository.AppUserRepository;
import com.enterprise.app.repository.TransactionRepository;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.time.Instant;

@Service
public class TransactionService {

    private final TransactionRepository transactionRepository;
    private final AppUserRepository userRepository;

    public TransactionService(TransactionRepository transactionRepository, AppUserRepository userRepository) {
        this.transactionRepository = transactionRepository;
        this.userRepository = userRepository;
    }

    @Transactional
    public Transaction createTransaction(Long userId, BigDecimal amount, String currency, String description) {
        AppUser user = userRepository.findById(userId).orElseThrow(() -> new IllegalArgumentException("User not found"));
        Transaction t = new Transaction();
        t.setUser(user);
        t.setAmount(amount);
        t.setCurrency(currency);
        t.setDescription(description);
        t.setStatus(TransactionStatus.PENDING);
        return transactionRepository.save(t);
    }

    @Transactional
    public Transaction markCompleted(String externalRef) {
        Transaction t = transactionRepository.findByExternalRef(externalRef)
                .orElseThrow(() -> new IllegalArgumentException("Transaction not found"));
        t.setStatus(TransactionStatus.COMPLETED);
        t.setProcessedAt(Instant.now());
        return transactionRepository.save(t);
    }

    @Transactional
    public Transaction markFailed(String externalRef) {
        Transaction t = transactionRepository.findByExternalRef(externalRef)
                .orElseThrow(() -> new IllegalArgumentException("Transaction not found"));
        t.setStatus(TransactionStatus.FAILED);
        t.setProcessedAt(Instant.now());
        return transactionRepository.save(t);
    }

    @Transactional(readOnly = true)
    public Page<Transaction> listUserTransactions(Long userId, Pageable pageable) {
        return transactionRepository.findByUserId(userId, pageable);
    }
}

